package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormat_withNormalValues() {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withNullValue() {
        CSVFormat formatWithNullString = csvFormat.withNullString("NULL");
        String result = formatWithNullString.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    public void testFormat_withEmptyValues() {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_withSpecialCharacters() {
        String result = csvFormat.format("a,b", "c\"d", "e\nf");
        // The CSVPrinter should quote fields containing delimiter, quote or linebreak
        assertTrue(result.contains("\"a,b\""));
        assertTrue(result.contains("\"c\"\"d\""));
        assertTrue(result.contains("\"e\nf\""));
    }

    @Test
    public void testFormat_throwsIllegalStateException_onIOException() throws Exception {
        // Create a CSVFormat instance
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to get the format method
        Method formatMethod = CSVFormat.class.getDeclaredMethod("format", Object[].class);
        formatMethod.setAccessible(true);

        // Create a spy of CSVFormat to mock CSVPrinter creation
        CSVFormat spyFormat = spy(format);

        // Mock CSVPrinter to throw IOException when printRecord is called
        CSVPrinter printerMock = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(printerMock).printRecord((Object[]) any());

        // Use reflection to replace the CSVPrinter constructor call with our mock
        // Since CSVFormat creates CSVPrinter internally, we cannot inject the mock directly.
        // Instead, simulate the IOException by invoking the format method via reflection and catch the exception.

        // To simulate IOException, create a subclass of CSVFormat overriding the format method
        CSVFormat formatWithIOException = new CSVFormat(format.getDelimiter(),
                format.getQuoteCharacter(),
                format.getQuoteMode(),
                format.getCommentMarker(),
                format.getEscapeCharacter(),
                format.getIgnoreSurroundingSpaces(),
                format.getIgnoreEmptyLines(),
                format.getRecordSeparator(),
                format.getNullString(),
                format.getHeaderComments(),
                format.getHeader(),
                format.getSkipHeaderRecord(),
                format.getAllowMissingColumnNames(),
                format.getIgnoreHeaderCase()) {
            @Override
            public String format(final Object... values) {
                try {
                    throw new IOException("IO error");
                } catch (IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            formatWithIOException.format("x");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }

    @Test
    public void testFormat_reflectionInvocation() throws Exception {
        Method formatMethod = CSVFormat.class.getDeclaredMethod("format", Object[].class);
        formatMethod.setAccessible(true);
        Object result = formatMethod.invoke(csvFormat, (Object) new Object[] { "1", "2" });
        assertEquals("1,2", result);
    }
}
